import { useEffect, useState } from "react";
import "../styles/Posts.css";

export default function ReferencePicker({ references, setReferences }) {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState([]);

    useEffect(() => {
        if (!query.trim()) {
            setResults([]);
            return;
        }

        const controller = new AbortController();

        fetch(`/api/posts/references/search?q=${encodeURIComponent(query)}`, {
            signal: controller.signal
        })
            .then(res => res.json())
            .then(data => setResults(data))
            .catch(() => {});

        return () => controller.abort();
    }, [query]);

    const addReference = (ref) => {
        if (
            references.some(
                r => r.type === ref.type && r.targetId === ref.targetId
            )
        ) return;

        setReferences(prev => [...prev, ref]);
        setQuery("");
        setResults([]);
    };

    const removeReference = (idx) => {
        setReferences(prev => prev.filter((_, i) => i !== idx));
    };

    return (
        <div className="reference-picker">
            <input
                className={"reference-textbox"}
                placeholder="Reference"
                value={query}
                onChange={e => setQuery(e.target.value)}
            />

            {results.length > 0 && (
                <div className="reference-results">
                    {results.map((r, i) => (
                        <div
                            key={i}
                            className="reference-result"
                            onClick={() => addReference(r)}
                        >
                            {r.displayText}
                            <span className="type">{r.type}</span>
                        </div>
                    ))}
                </div>
            )}

            {references.length > 0 && (
                <div className="reference-list">
                    {references.map((ref, i) => (
                        <div key={i} className="reference-item">
                            <span>{ref.title || ref.label || ref.url}</span>

                            <button
                                className="remove-ref"
                                onClick={() =>
                                    setReferences(prev =>
                                        prev.filter((_, idx) => idx !== i)
                                    )
                                }
                            >
                                ✕
                            </button>
                        </div>
                    ))}
                </div>
            )}

        </div>
    );
}
